# Simple BPE tokenizer implementation
def learn_bpe(corpus: list[str], num_merges: int) -> dict[tuple[str, str], str]:
    # Initialize: split words into characters
    vocab = {}
    for word in corpus:
        chars = tuple(word) + ('</w>',)
        vocab[chars] = vocab.get(chars, 0) + 1

    merges = {}
    for _ in range(num_merges):
        pairs = {}
        for word, freq in vocab.items():
            for i in range(len(word) - 1):
                pair = (word[i], word[i + 1])
                pairs[pair] = pairs.get(pair, 0) + freq
        if not pairs:
            break
        best = max(pairs, key=pairs.get)
        merges[best] = best[0] + best[1]
        new_vocab = {}
        for word, freq in vocab.items():
            new_word = []
            i = 0
            while i < len(word):
                if i < len(word) - 1 and (word[i], word[i+1]) == best:
                    new_word.append(merges[best])
                    i += 2
                else:
                    new_word.append(word[i])
                    i += 1
            new_vocab[tuple(new_word)] = freq
        vocab = new_vocab
    return merges

