from langchain.chains.summarize import load_summarize_chain
from langchain.text_splitter import RecursiveCharacterTextSplitter

# Approach 1: Truncation (simplest, lossy)
def truncate(text: str, max_tokens: int) -> str:
    tokens = tokenizer.encode(text)
    return tokenizer.decode(tokens[:max_tokens])

# Approach 2: Map-Reduce (parallel processing)
def map_reduce_summarize(docs: list[str], llm):
    splitter = RecursiveCharacterTextSplitter(chunk_size=4000, chunk_overlap=200)
    chunks = splitter.create_documents(docs)
    chain = load_summarize_chain(llm, chain_type='map_reduce')
    return chain.invoke(chunks)

# Approach 3: Iterative refinement
def refine_summary(docs: list[str], llm):
    chain = load_summarize_chain(llm, chain_type='refine')
    return chain.invoke(docs)

# Approach 4: Sliding window with overlap
def sliding_window_qa(text: str, question: str, llm, window_size: int = 4000):
    splitter = RecursiveCharacterTextSplitter(chunk_size=window_size, chunk_overlap=500)
    chunks = splitter.split_text(text)
    answers = []
    for chunk in chunks:
        answer = llm.invoke(f'Context: {chunk}\nQuestion: {question}')
        answers.append(answer)
    return llm.invoke(f'Combine these partial answers: {answers}\nOriginal question: {question}')
