from collections import deque
import tiktoken

class ConversationMemory:
    def __init__(self, max_tokens: int = 4000, model: str = 'gpt-4'):
        self.messages: deque[dict] = deque()
        self.system_prompt: str = ''
        self.max_tokens = max_tokens
        self.enc = tiktoken.encoding_for_model(model)

    def add(self, role: str, content: str) -> None:
        self.messages.append({'role': role, 'content': content})
        self._trim()

    def _count_tokens(self, msg: dict) -> int:
        return len(self.enc.encode(msg['content'])) + 4  # role overhead

    def _trim(self) -> None:
        total = sum(self._count_tokens(m) for m in self.messages)
        total += len(self.enc.encode(self.system_prompt))
        while total > self.max_tokens and len(self.messages) > 2:
            removed = self.messages.popleft()
            total -= self._count_tokens(removed)

    def get_messages(self) -> list[dict]:
        return list(self.messages)

# Persistent memory with summary compression:
class SummarizingMemory:
    def __init__(self, llm, max_messages: int = 20):
        self.llm = llm
        self.summary: str = ''
        self.recent: deque[dict] = deque(maxlen=max_messages)

    def add(self, role: str, content: str) -> None:
        self.recent.append({'role': role, 'content': content})
        if len(self.recent) == self.recent.maxlen:
            self._compress()

    def _compress(self) -> None:
        old_messages = list(self.recent)[:10]
        text = '\n'.join(f"{m['role']}: {m['content']}" for m in old_messages)
        self.summary = self.llm.invoke(
            f'Previous summary: {self.summary}\nNew messages: {text}\nUpdate the summary.'
        )
        for _ in range(10):
            self.recent.popleft()
