import hashlib
import random
from dataclasses import dataclass
from scipy import stats
import numpy as np

@dataclass
class ExperimentConfig:
    name: str
    control_model: str
    treatment_model: str
    traffic_pct: float  # fraction to treatment (0.0 - 1.0)
    min_samples: int
    confidence_level: float = 0.95

class ModelABTest:
    def __init__(self, config: ExperimentConfig):
        self.config = config
        self.control_metrics: list[float] = []
        self.treatment_metrics: list[float] = []

    def route_request(self, user_id: str) -> str:
        # Deterministic routing: same user always gets same variant
        hash_val = int(hashlib.md5(f'{self.config.name}:{user_id}'.encode()).hexdigest(), 16)
        if (hash_val % 1000) < self.config.traffic_pct * 1000:
            return self.config.treatment_model
        return self.config.control_model

    def record_metric(self, variant: str, score: float) -> None:
        if variant == self.config.control_model:
            self.control_metrics.append(score)
        else:
            self.treatment_metrics.append(score)

    def analyze(self) -> dict:
        if len(self.control_metrics) < self.config.min_samples:
            return {'status': 'insufficient_data'}
        t_stat, p_value = stats.ttest_ind(self.treatment_metrics, self.control_metrics)
        significant = p_value < (1 - self.config.confidence_level)
        return {
            'control_mean': np.mean(self.control_metrics),
            'treatment_mean': np.mean(self.treatment_metrics),
            'p_value': p_value,
            'significant': significant,
            'recommendation': 'deploy' if significant and np.mean(self.treatment_metrics) > np.mean(self.control_metrics) else 'keep_control'
        }
