from prefect import flow, task
from prefect.tasks import task_input_hash
from datetime import timedelta
import pandas as pd
from great_expectations.core import ExpectationSuite

@task(cache_key_fn=task_input_hash, cache_expiration=timedelta(hours=1))
def extract_data(source: str) -> pd.DataFrame:
    return pd.read_parquet(source)

@task
def validate_data(df: pd.DataFrame) -> pd.DataFrame:
    # Great Expectations validation
    assert df.shape[0] > 0, 'Empty dataset'
    assert df['user_id'].nunique() > 100, 'Too few users'
    null_rate = df.isnull().mean()
    assert (null_rate < 0.1).all(), f'High null rate: {null_rate[null_rate >= 0.1]}'
    return df

@task
def compute_features(df: pd.DataFrame) -> pd.DataFrame:
    df['purchase_frequency'] = df.groupby('user_id')['order_id'].transform('count')
    df['avg_order_value'] = df.groupby('user_id')['amount'].transform('mean')
    df['days_active'] = (df['last_login'] - df['signup_date']).dt.days
    return df

@task
def train_model(df: pd.DataFrame) -> dict:
    from sklearn.ensemble import GradientBoostingClassifier
    X = df[['purchase_frequency', 'avg_order_value', 'days_active']]
    y = df['churned']
    model = GradientBoostingClassifier().fit(X, y)
    return {'accuracy': model.score(X, y), 'model': model}

@flow(name='ml-training-pipeline')
def training_pipeline(data_path: str):
    raw = extract_data(data_path)
    validated = validate_data(raw)
    features = compute_features(validated)
    result = train_model(features)
    return result
