import anthropic
import json
from pydantic import BaseModel, ValidationError
from typing import Optional

# Approach 1: Prompt engineering with examples
def extract_json_prompt(text: str) -> dict:
    client = anthropic.Anthropic()
    response = client.messages.create(
        model='claude-sonnet-4-20250514', max_tokens=500, temperature=0,
        system='You extract structured data. Always respond with valid JSON only. No explanation.',
        messages=[{'role': 'user', 'content': f'Extract name, email, and phone from:\n{text}'}]
    )
    return json.loads(response.content[0].text)

# Approach 2: Tool use (most reliable)
def extract_with_tools(text: str) -> dict:
    client = anthropic.Anthropic()
    response = client.messages.create(
        model='claude-sonnet-4-20250514', max_tokens=500,
        tools=[{
            'name': 'extract_contact',
            'description': 'Extract contact information',
            'input_schema': {
                'type': 'object',
                'properties': {
                    'name': {'type': 'string'},
                    'email': {'type': 'string', 'format': 'email'},
                    'phone': {'type': 'string'}
                },
                'required': ['name']
            }
        }],
        tool_choice={'type': 'tool', 'name': 'extract_contact'},
        messages=[{'role': 'user', 'content': f'Extract contact info: {text}'}]
    )
    for block in response.content:
        if block.type == 'tool_use':
            return block.input
    return {}

# Approach 3: Pydantic validation
class Contact(BaseModel):
    name: str
    email: Optional[str] = None
    phone: Optional[str] = None

def validated_extract(text: str) -> Contact:
    raw = extract_with_tools(text)
    return Contact(**raw)  # raises ValidationError if invalid
```

Reliability ranking: tool use > JSON mode > prompt engineering. Tool use forces the model to conform to the schema.
